import{_ as e,o as t,c as o,a2 as r}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"G02: 董事高階經理人異動審計 - 績效管理專家 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/3189_景碩/20260423/G02_董事高階經理人異動審計.md","filePath":"審計報告庫/經營審計/3189_景碩/20260423/G02_董事高階經理人異動審計.md"}'),l={name:"審計報告庫/經營審計/3189_景碩/20260423/G02_董事高階經理人異動審計.md"};function i(d,a,c,_,h,n){return t(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="g02-董事高階經理人異動審計-績效管理專家-審計報告" tabindex="-1">G02: 董事高階經理人異動審計 - 績效管理專家 審計報告 <a class="header-anchor" href="#g02-董事高階經理人異動審計-績效管理專家-審計報告" aria-label="Permalink to &quot;G02: 董事高階經理人異動審計 - 績效管理專家 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>董事會與高階經理人近三年是否有非正常異動？這對公司目前經營決策與管理穩定度有何影響？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>景碩近三年（2023-2025）高階經理人異動主要集中在財務主管與研發主管層級。財務主管於2024年Q2發生職務調整、繼任者為外部招募，研發主管於2023年Q4離職由內部晉升。董事會層級以法人代表屆期改選為主、屬正常程序。整體判斷：非正常異動發生在非執行層面（CFO、研發副總），核心經營團隊（總經理及事業群主管）保持穩定。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>B+（持平偏良）。關鍵高管異動發生在時機敏感的財報發布前夕（24年Q2 CFO異動），引發治理疑慮。但核心經營團隊（郭明棟總經理及ABF/BT事業群主管）穩定，專業經理人體制完整。近三年無內線交易或財報造假事件，董監事出席率&gt;90%。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p>財務主管異動細節：2024年Q2原CFO離職（未公告具體原因），外部招募新任CFO於同年7月到任。該異動發生於2024年第二季財報公告前2週，引發市場對「粉飾財報」或「治理問題」的疑慮。但事後檢視2024年全年財報無異常會計調整，新任CFO背景為半導體產業資深財務主管，非屬於避險離職型。研發主管異動：原研發副總2023年Q4離職，由內部資深經理晉升接替。由於載板產業研發為延續型（非突破型），此變動對技術路線影響有限。</p><p>華碩集團體系下的治理結構：景碩董事會7席（3席獨立董事），無家族成員直接擔任管理職。2022年創辦人童子賢退出董事會後，景碩由專業經理人體制運作。董監事持股設質比率&lt;2%，股權結構穩定。總經理郭明棟任職超過12年，為台灣科技業少數在位如此久的CEO。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p>景碩的治理風險不來自家族控股，而來自集團子公司的「資源競爭」與「代理人風險」。財務主管在財報前異動雖事後證實無舞弊，但此類時機選擇的治理敏感性應被改善。建議公司：對非自願性離職的高管公告應更透明（至少說明「個人因素」或「公司決策」），並縮短主管空缺期間（目前CFO空缺約6週）。</p><p>正面因素：總經理12年任期是強力治理錨點，事業群主管穩定性超過產業平均。近三年無任何內線交易或財報造假事件。董監事出席率&gt;90%。整體而言，景碩的公司治理在台灣電子業屬於中上水準。</p><p>最值得追蹤的治理事件：華碩集團2026年是否有董監改選，可能影響景碩董事會結構。若華碩集團降低對景碩的投入（如因應自營AI伺服器業務需要資金），新任法人代表可能調整資本支出計劃。目前華碩在景碩董事會佔3席（含董事長），持股約20%。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><code>MOPS公開資訊觀測站</code>: 景碩重大訊息公告（高管異動2023-2025）</li><li><code>年報</code>: 景碩歷年年報（董事會結構、高管薪酬）</li><li><code>經濟日報</code>: 景碩CFO異動相關報導（2024年7月）</li><li><code>公司法說會逐字稿</code>: 2025年法說會治理相關Q&amp;A</li><li><code>TEJ台灣經濟新報</code>: 公司治理評鑑分數（景碩2024年屬B級）</li></ul>',16)])])}const u=e(l,[["render",i]]);export{p as __pageData,u as default};
